%{
ES 115 CLASS PROJECT PROBLEM 6.0
PROBLEM TITLE: Vehicle Braking Distance Simulator
DESCRIPTION: Simulates stopping distance for different initial speeds using
             time-stepped deceleration in different conditions.
PURPOSE: To model and simulate vehicle braking behavior under varying
         initial speeds and road conditions in order to analyze stopping distance,
         deceleration, and overall safety performance.
INPUTS:
    ~ Initial velocity
    ~ Road Surface Condition
    ~ Gravitational acceleration
    ~ Simulation time step
OUTPUTS:
    ~ Vehicle velocity
    ~ Elapsed time
    ~ Stopping Distance
ENGINNERING ALGORITHMS:
- Accepts user defined initial velocity
- Initialize, position, time, and deceleration
- Update velocity and time using time-stepping 
- Animate vehicle motion while updating real time data
- Stop simulation when velocity reaches zero
MATLAB TOOLS/FUNCTIONS:
- Real time animation
- Drawnow, pause
- uiaxes, rectangle
- uifigure, uieditfield, uibutton
%}
%[text] ![](text:image:4d1b)
function brakingSimulatorApp
% Braking Distance Simulator - UI with dynamic axis expansion so car stays visible

    % Create UI Figure
    fig = uifigure('Name','Braking Distance Simulator','Position',[100 100 700 460]);

    % Velocity Input
    uilabel(fig,'Position',[20 400 150 20],'Text','Initial Velocity (m/s):');
    velInput = uieditfield(fig,'numeric','Position',[180 400 100 22],'Value',20);

    % Road Type Dropdown
    % Create label for road-type selector
    uilabel(fig,'Position',[300 400 100 20],'Text','Road Type:');
    % Dropdown with three surface conditions; default is 'Dry'
    roadType = uidropdown(fig, ...
        'Position',[380 400 120 22], ...
        'Items',{'Dry','Wet','Icy'}, ...
        'Value','Dry');

    % Start Button
    startBtn = uibutton(fig, ...
        'Text','Start Simulation', ...
        'Position',[520 395 110 30], ...
        'ButtonPushedFcn',@(btn,event) runSimulation());

    % Reset Button (left of Start)
    resetBtn = uibutton(fig, ...
        'Text', 'Reset', ...
        'Position', [390 360 110 30], ...
        'ButtonPushedFcn',@(btn,event) resetSimulation());

    % Axes
    ax = uiaxes(fig,'Position',[50 120 600 240]);
    xlim(ax,[0 200]);
    ylim(ax,[0 10]);
    ax.XTick = [];
    ax.YTick = [];
    title(ax,'Braking Simulation');

    % Labels
    velLabel = uilabel(fig,'Position',[50 60 200 20],'Text','Velocity: 0 m/s');
    timeLabel = uilabel(fig,'Position',[300 60 200 20],'Text','Time: 0 s');

    % Car placeholder (rectangle) and initial plot setup
    car = rectangle(ax,'Position',[0 2 10 4],'FaceColor','blue');

    % ---------------- Simulation Function ----------------
    function runSimulation()
        % Get user input
        v = velInput.Value;

        % Road-dependent friction
        switch roadType.Value
            case 'Dry'
                mu = 0.7;
            case 'Wet'
                mu = 0.4;
            case 'Icy'
                mu = 0.1;
            otherwise
                mu = 0.7;
        end

        g = 9.81;
        a = -mu * g;

        dt = 0.05;
        x = 0;
        t = 0;

        % Reset car position and axes
        car.Position = [0 2 10 4];
        cla(ax);
        xlim(ax,[0 200]);
        ylim(ax,[0 10]);
        ax.XTick = [];
        ax.YTick = [];
        car = rectangle(ax,'Position',[0 2 10 4],'FaceColor','blue');

        carWidth = car.Position(3);
        rightMargin = 20; % margin to keep car visible

        % Simulation loop
        while v > 0 && isvalid(car)
            % Physics update
            v = v + a * dt;
            if v < 0
                v = 0;
            end

            x = x + v * dt;
            t = t + dt;

            % Extend x-axis if car approaches right limit
            currentXLim = ax.XLim;
            if x + carWidth + rightMargin > currentXLim(2)
                newMax = x + carWidth + rightMargin;
                xlim(ax, [currentXLim(1) newMax]);
            end

            % Update car position
            pos = car.Position;
            pos(1) = x;
            car.Position = pos;

            % Update labels
            velLabel.Text = sprintf('Velocity: %.2f m/s', v);
            timeLabel.Text = sprintf('Time: %.2f s', t);

            drawnow;
            pause(0.02);

            % Safety: break if axis limit becomes extremely large
            if ax.XLim(2) > 1e4
                break;
            end
        end
    end

    % ---------------- Reset Function ----------------
    function resetSimulation()
        velInput.Value = 20;
        roadType.Value = 'Dry';
        velLabel.Text = 'Velocity: 0 m/s';
        timeLabel.Text = 'Time: 0 s';

        if isvalid(car)
            car.Position = [0 2 10 4];
        end

        cla(ax);
        xlim(ax,[0 200]);
        ylim(ax,[0 10]);
        ax.XTick = [];
        ax.YTick = [];
        car = rectangle(ax,'Position',[0 2 10 4],'FaceColor','blue');
    end

end

